\nimport SwiftUI\n\nstruct RenameWizardView: View {\n    @StateObject private var viewModel = RenameWizardViewModel()\n    @Binding var isPresented: Bool\n    \n    @State private var showFileImporter = false\n\n    var body: some View {\n        VStack(spacing: 0) {\n            // Header\n            Text(\"✨ Assistente de Renomeação\")\n                .font(.largeTitle)\n                .fontWeight(.bold)\n                .padding()\n                .frame(maxWidth: .infinity)\n                .background(Color(.windowBackgroundColor))\n                .overlay(alignment: .topTrailing) {\n                    Button(action: { isPresented = false }) {\n                        Image(systemName: \"xmark.circle.fill\")\n                            .font(.title2)\n                            .foregroundColor(.gray)\n                    }\n                    .buttonStyle(.plain)\n                    .padding()\n                }\n\n            Divider()\n\n            // Main content based on step\n            Group {\n                switch viewModel.currentStep {\n                case .selectFiles:\n                    step1_SelectFiles()\n                case .buildName:\n                    step2_BuildName()\n                case .preview:\n                    step3_FinalPreview()\n                case .progress:\n                    step4_Progress()\n                case .complete:\n                    step5_Complete()\n                }\n            }\n            .frame(maxWidth: .infinity, maxHeight: .infinity)\n        }\n        .frame(width: 650, height: 600)\n        .fileImporter(isPresented: $showFileImporter, allowedContentTypes: [.content], allowsMultipleSelection: true) { result in\n            do {\n                viewModel.selectedFiles = try result.get()\n                viewModel.generatePreviews() // Initial preview\n            } catch {\n                // Handle error\n                print(\"Error selecting files: \\(error.localizedDescription)\")\n            }\n        }\n    }\n}\n\n// MARK: - Wizard Steps as Subviews\nextension RenameWizardView {\n\n    @ViewBuilder\n    private func step1_SelectFiles() -> some View {\n        VStack(spacing: 20) {\n            Text(\"Passo 1: Escolha os Ficheiros\")\n                .font(.title2)\n                .fontWeight(.semibold)\n            \n            Button(\"📂 Selecionar Ficheiros para Renomear...\") {\n                showFileImporter = true\n            }\n            \n            if !viewModel.selectedFiles.isEmpty {\n                Text(\"\\(viewModel.selectedFiles.count) ficheiros selecionados.\")\n                    .foregroundColor(.secondary)\n            }\n            \n            Spacer()\n            \n            HStack {\n                Button(\"Cancelar\") { isPresented = false }\n                Spacer()\n                Button(\"Continuar →\") {\n                    viewModel.currentStep = .buildName\n                }\n                .disabled(viewModel.selectedFiles.isEmpty)\n            }\n        }\n        .padding(30)\n    }\n\n    @ViewBuilder\n    private func step2_BuildName() -> some View {\n        HStack(spacing: 0) {\n            // Left Panel: Builder\n            VStack(alignment: .leading) {\n                Text(\"Passo 2: Construa o Novo Nome\").font(.title2).fontWeight(.semibold).padding(.bottom)\n                \n                Text(\"Adicionar Componentes\").font(.headline)\n                HStack {\n                    ForEach(FilenameComponent.ComponentType.allCases, id: \\.self) { type in\n                        Button(type.rawValue) { viewModel.addComponent(type) }\n                    }\n                }\n                \n                Text(\"Padrão Atual\").font(.headline).padding(.top)\n                List {\n                    ForEach($viewModel.nameComponents, id: \\.self) { $component in\n                        HStack {\n                            Text(component.type.rawValue)\n                            if component.type == .customText {\n                                TextField(\"Texto...\", text: $component.value, onCommit: {\n                                    viewModel.generatePreviews()\n                                })\n                                .textFieldStyle(.roundedBorder)\n                            }\n                        }\n                    }\n                    .onDelete(perform: viewModel.removeComponent)\n                    .onMove(perform: viewModel.moveComponent)\n                }\n                .listStyle(.bordered)\n                .frame(minHeight: 200)\n                \n                Spacer()\n                \n                HStack {\n                    Button(\"← Voltar\") { viewModel.currentStep = .selectFiles }\n                    Spacer()\n                    Button(\"Pré-visualizar →\") { viewModel.currentStep = .preview }\n                }\n            }\n            .padding()\n            .frame(width: 300)\n            \n            Divider()\n            \n            // Right Panel: Live Preview\n            VStack {\n                Text(\"Pré-visualização em Tempo Real\").font(.headline)\n                List(viewModel.previews.prefix(10)) { preview in\n                    HStack {\n                        Text(preview.originalURL.lastPathComponent)\n                            .foregroundColor(.secondary)\n                            .lineLimit(1)\n                            .truncationMode(.middle)\n                        Spacer()\n                        Image(systemName: \"arrow.right\")\n                        Spacer()\n                        Text(preview.newFilename)\n                            .fontWeight(.bold)\n                            .lineLimit(1)\n                            .truncationMode(.tail)\n                    }\n                    .font(.system(.body, design: .monospaced))\n                }\n                .listStyle(.plain)\n            }\n            .padding()\n        }\n        .onChange(of: viewModel.nameComponents) { _ in\n            viewModel.generatePreviews()\n        }\n    }\n    \n    @ViewBuilder\n    private func step3_FinalPreview() -> some View {\n        VStack {\n            Text(\"Passo 3: Pré-visualização Final\")\n                .font(.title2).fontWeight(.semibold).padding()\n            \n            Text(\"Confirme as alterações. Serão renomeados \\(viewModel.selectedFiles.count) ficheiros.\").padding(.bottom)\n            \n            List(viewModel.previews) { preview in\n                HStack {\n                    Text(preview.originalURL.lastPathComponent)\n                        .foregroundColor(.secondary)\n                        .frame(width: 250, alignment: .leading)\n                        .lineLimit(1)\n                        .truncationMode(.middle)\n                    Image(systemName: \"arrow.right\")\n                    Text(preview.newFilename)\n                        .fontWeight(.bold)\n                        .frame(maxWidth: .infinity, alignment: .leading)\n                        .lineLimit(1)\n                        .truncationMode(.tail)\n                }\n                .font(.system(.body, design: .monospaced))\n            }\n            .listStyle(.bordered)\n            \n            Spacer()\n            \n            HStack {\n                Button(\"← Voltar\") { viewModel.currentStep = .buildName }\n                Spacer()\n                Button(\"✅ Aplicar Novos Nomes\") {\n                    Task { await viewModel.startRenaming() }\n                }\n            }\n        }\n        .padding(30)\n    }\n    \n    @ViewBuilder\n    private func step4_Progress() -> some View {\n        // (Identical to Organizer Wizard's Progress View)\n        VStack(spacing: 20) {\n            Text(\"A Renomear os seus ficheiros...\")\n                .font(.title2).fontWeight(.semibold)\n            ProgressView(value: viewModel.progress)\n                .progressViewStyle(.linear)\n            Text(viewModel.progressMessage)\n                .font(.callout).foregroundColor(.secondary)\n            Spacer()\n        }\n        .padding(30)\n    }\n\n    @ViewBuilder\n    private func step5_Complete() -> some View {\n        // (Identical to Organizer Wizard's Complete View)\n        VStack(spacing: 20) {\n            Text(\"🎉 Sucesso!\")\n                .font(.largeTitle).fontWeight(.bold).foregroundColor(.green)\n            Text(\"\\(viewModel.selectedFiles.count) ficheiros foram renomeados com sucesso.\")\n            Spacer()\n            HStack {\n                Spacer()\n                Button(\"Concluir\") {\n                    viewModel.reset()\n                    isPresented = false\n                }\n                .keyboardShortcut(.defaultAction)\n                Spacer()\n            }\n        }\n        .padding(30)\n    }\n}\n